def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 10:
            for a in range(10, 0, -1):
                for b in range(1, a + 5):
                    power = (ratio - a) ** 6
                    div = (a*b*1.2 + 1)
                    trig = np.tan(ratio * b / (a + 1.5))
                    priority += (power / div) * trig * (np.sin(b + i) ** 2)
            priority += (np.cosh(ratio - 9) * np.sin(ratio * 2)) ** 2.1
            if bin_cap < item * 0.5:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 5
        elif 6 < ratio <= 10:
            for p in range(2, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 3):
                    factor = ((ratio - p) ** 4) * np.cos(ratio * q / p)
                    penalty = np.tanh(factor / (q + 1)) * 1.7
                    priority += penalty
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3
            if i % 2 == 0:
                priority += np.sin(ratio * i) * 0.9
            else:
                priority -= np.cos(ratio * i) * 0.7
        elif 3 < ratio <= 6:
            acc = 0
            for r in range(1, 20):
                acc += ((ratio - 3) ** r) / (r * 2.2) * np.sin(r * ratio * 0.9)
            priority = acc * np.cos(9 * ratio) - np.log(ratio) * 8 + np.tanh(5 * (6 - ratio)) * 2.3
            if bin_cap > item * 3:
                priority -= np.exp(-ratio) * 6
            else:
                priority += np.sqrt(bin_cap / (item + 0.1)) * 3
        elif 1.5 <= ratio <= 3:
            s = 0
            for n in range(1, 25):
                s += ((ratio - 1.5) ** n) / (n**1.5 + 1) * np.cos(n * ratio * 1.3)
            priority = s * np.sin(8 * ratio) - np.log(ratio) * 7 + np.tanh(3 * (3 - ratio)) * 2.1
            for m in range(1, 6):
                priority += np.sin(m * ratio * i * 0.8) * ((ratio - 1.5) ** m) / (m + 0.5)
        elif 0.9 <= ratio < 1.5:
            sum_s = 0
            for k in range(1, 18):
                sum_s += ((1.5 - ratio) ** k) / (k**2 + 1) * np.cos(3 * k * ratio)
            penalty = np.exp(-2 / (ratio + 0.1))
            priority = sum_s + penalty
            if bin_cap < item * 1.2:
                priority += np.sqrt(item / (bin_cap + 0.1)) * 5
            else:
                priority -= np.cos(15 * ratio) * 3
            for j in range(1, 8):
                priority += np.sin(j * ratio * i * 1.2) * ((ratio - 0.9) ** j) / (j + 1)
        elif 0.4 <= ratio < 0.9:
            s = 0
            for u in range(1, 22):
                s += ((0.9 - ratio) ** u) / (u * 5) * np.sin(u * ratio * 2)
            priority = s
            if (i + int(item * 2)) % 5 == 1:
                priority *= np.log1p(bin_cap + 4) * 1.8
            else:
                priority /= (np.sqrt(bin_cap + 2) + 2.5)
            for v in range(1, 9):
                priority += ((0.9 - ratio) ** v) * np.cos(v * item * 1.5) * 0.9
        elif 0.15 <= ratio < 0.4:
            s = 0
            for w in range(1, 20):
                s += ((0.4 - ratio) ** w) / (w * 4.5) * np.cos(w * ratio * 2.2)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.7) % 5 == 2:
                priority *= 3.1
            else:
                priority /= 3.1
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.7) * 3.7
            for x in range(1, 9):
                priority += ((0.4 - ratio) ** x) / (x * 6.5) * np.sin(item * x * 1.3)
        else:
            s = 0
            for y in range(1, 17):
                s += ((0.15 - ratio) ** y) / (y * 6) * np.sin(y * item * 1.2)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 1:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6.5
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for z in range(1, 10):
                priority += ((0.15 - ratio) ** z) / (z * 8) * np.cos(item * z * 0.85)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx * 2) % 4 == 0:
                priority += np.sin(ratio * (i + idx)) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx)) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.15) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.15) * 0.7
        priorities[i] = priority
    return priorities
